  id: `python-process-${trialId}`,
  run: async (payload: PythonProcessPayload) => {
    const result = await python.runScript(
      "./scripts/process.py",
      payload.numbers.map(String)
    );

    const output = result.stdout.trim();
    const match = output.match(/Average:\s*([0-9.+-eE]+)/);
    if (!match) {
